async function printMessage(message) {
    let chatData = { content: message };
    ChatMessage.applyRollMode(chatData, game.settings.get("core", "rollMode"));
    ChatMessage.create(chatData, {})
};

async function rollOracle(tableID, lowerCase = true) {
    let table = await fromUuid(tableID);
    let roll = await table.roll();
    let result = roll.results[0].text;

    if (result.startsWith("@Compendium")) {
        table = await fromUuid(result.slice(1).replace("[", ".").split("]")[0]);
        roll = await table.roll();
        result = roll.results[0].text;
    }

    if (result == "Roll twice") {
        let results = ["Roll twice", "Roll twice"];
        for (let index = 0; index < results.length; index++) {
            let element = results[index];
            do {
                const table = await fromUuid(tableID);
                let roll = await table.roll();
                element = roll.results[0].text.toLowerCase();
            } while (element == "roll twice");
            results[index] = element;
        };
        result = results[0] + " and " + results[1];
    }
    return lowerCase ? result.toLowerCase() : result;
};

let title = "<h3><strong>Oracle Quest - Gigafoundries</strong></h3>";
let message = "A " + await rollOracle("Compendium.ancient-wonders.ancientwondersoracles.RollTable.mEWovsWhwKc4EYn4") + " settlement has been attempting to reactivate an offline gigafoundry themselves, as their " + await rollOracle("Compendium.ancient-wonders.ancientwondersoracles.RollTable.165pYBMpRkAewRXO") + " faction refuses to help with the endeavor. The community is now seeking intrepid delvers to aid them, convinced that restoring the massive facility will allow them to complete their " + await rollOracle("Compendium.ancient-wonders.ancientwondersoracles.RollTable.bEcncvEiOdNI2M2c") + " project and secure their future. Yet the faction's refusal reaises some troubling questions - whether it stems from political disputes, hidden dangers within the foundry, or a desire to keep the settlement dependent on outside aid. What risks or opportunities lie dormant in the gigafoundry's silent halls? How might its reactivation rshape the balance of power for the settlement?"

// Print the message
printMessage(title + message);
